#!/usr/bin/env node
// @sauravvarma/catalyst-cloudflare CLI.
//
//   npx catalyst-cloudflare init [--name <worker-name>] [--routes /,/api/*]
//
// One-shot, idempotent opt-in. It writes only the small, per-app bits into the app's
// package.json (the 3 worker scripts + a `catalystCloudflare` config stanza) and adds
// the generated artifacts to .gitignore. The heavy, static wiring (worker/index.js and
// the full wrangler.jsonc) is generated by prebuild.mjs on every `build:worker`, so it
// is never copied into the app and stays in sync with the installed adapter version.
import { readFileSync, writeFileSync, existsSync } from "node:fs"
import { join } from "node:path"
import { ADAPTER, SCRIPTS, slugify } from "../lib/adapter.mjs"

const ROOT = process.cwd()

function parseArgs(argv) {
    const args = {}
    for (let i = 0; i < argv.length; i++) {
        const a = argv[i]
        if (a === "--name") args.name = argv[++i]
        else if (a === "--routes") args.routes = argv[++i]
        else if (a.startsWith("--name=")) args.name = a.slice(7)
        else if (a.startsWith("--routes=")) args.routes = a.slice(9)
    }
    return args
}

function ensureGitignore(entries) {
    const path = join(ROOT, ".gitignore")
    const existing = existsSync(path) ? readFileSync(path, "utf-8") : ""
    const have = new Set(existing.split("\n").map((l) => l.trim()))
    const missing = entries.filter((e) => !have.has(e))
    if (!missing.length) return []
    const prefix = existing && !existing.endsWith("\n") ? "\n" : ""
    writeFileSync(path, existing + prefix + `\n# ${ADAPTER} (generated)\n` + missing.join("\n") + "\n")
    return missing
}

function init(argv) {
    const args = parseArgs(argv)
    const pkgPath = join(ROOT, "package.json")
    if (!existsSync(pkgPath)) {
        console.error(`catalyst-cloudflare init: no package.json in ${ROOT}. Run this from your Catalyst app root.`)
        process.exit(1)
    }
    const pkg = JSON.parse(readFileSync(pkgPath, "utf-8"))
    const changed = []

    // 1. catalystCloudflare stanza (only fill what's missing; never clobber user values).
    const cc = pkg.catalystCloudflare || {}
    if (args.name) cc.name = args.name
    else if (!cc.name) cc.name = slugify(pkg.name)
    if (args.routes) cc.routes = args.routes.split(",").map((r) => r.trim()).filter(Boolean)
    else if (!Array.isArray(cc.routes)) cc.routes = ["/"]
    if (JSON.stringify(pkg.catalystCloudflare) !== JSON.stringify(cc)) {
        pkg.catalystCloudflare = cc
        changed.push("catalystCloudflare config")
    }

    // 2. worker scripts (add only if absent so we don't stomp customized scripts).
    pkg.scripts = pkg.scripts || {}
    for (const [k, v] of Object.entries(SCRIPTS)) {
        if (!pkg.scripts[k]) {
            pkg.scripts[k] = v
            changed.push(`script "${k}"`)
        }
    }

    writeFileSync(pkgPath, JSON.stringify(pkg, null, 4) + "\n")

    // 3. gitignore the generated artifacts.
    const ignored = ensureGitignore([
        "worker/index.js",
        "worker/fs-assets.generated.js",
        "wrangler.jsonc",
        "dist",
        ".wrangler",
    ])

    console.log(`catalyst-cloudflare init: worker name "${cc.name}", routes ${JSON.stringify(cc.routes)}`)
    console.log(changed.length ? `  updated package.json: ${changed.join(", ")}` : "  package.json already configured")
    if (ignored.length) console.log(`  added to .gitignore: ${ignored.join(", ")}`)
    console.log("\nNext:")
    console.log("  npm i -D wrangler   # if not already installed")
    console.log("  npm run deploy:worker")
}

const [cmd, ...rest] = process.argv.slice(2)
if (cmd === "init") {
    init(rest)
} else {
    console.log("Usage: catalyst-cloudflare init [--name <worker-name>] [--routes /,/api/*]")
    process.exit(cmd ? 1 : 0)
}
